    private fun handleRunTask(intent: Intent, startId: Int) {
        val taskType = intent.getStringExtra(EXTRA_TASK_TYPE)?.lowercase()
        val force = intent.getBooleanExtra(EXTRA_FORCE, false)
        val dryRun = intent.getBooleanExtra(EXTRA_DRY_RUN, false)
        val target = intent.getStringExtra(EXTRA_TARGET)
        val maxAgeDays = intent.getIntExtra(EXTRA_MAX_AGE_DAYS, 30)
        val callerTag = intent.getStringExtra(EXTRA_CALLER_TAG)

        val taskId = intent.getStringExtra(EXTRA_TASK_ID)?.takeIf { it.isNotBlank() } ?: UUID.randomUUID().toString()

        if (taskType != "sync" && taskType != "cleanup") {
            Log.w(TAG, "Rejected taskId=$taskId invalid taskType=$taskType callerTag=$callerTag")
            stopSelfResult(startId)
            return
        }

        if (running.containsKey(taskId)) {
            Log.w(TAG, "Rejected duplicate taskId=$taskId taskType=$taskType callerTag=$callerTag")
            stopSelfResult(startId)
            return
        }

        activeCount.incrementAndGet()

        val job = scope.launch {
            try {
                Log.i(TAG, "Accepted taskId=$taskId type=$taskType force=$force dryRun=$dryRun target=$target maxAgeDays=$maxAgeDays callerTag=$callerTag")
                when (taskType) {
                    "sync" -> performSync(taskId, force, dryRun, target, callerTag)
                    "cleanup" -> performCleanup(taskId, force, dryRun, target, maxAgeDays, callerTag)
                }
                Log.i(TAG, "Completed taskId=$taskId type=$taskType")
            } catch (t: Throwable) {
                Log.e(TAG, "Failed taskId=$taskId type=$taskType", t)
            } finally {
                running.remove(taskId)
                val remaining = activeCount.decrementAndGet()
                if (remaining <= 0) {
