                }
            }
        }

        running[taskId] = job
        stopSelfResult(startId)
    }

    private fun handleCancelTask(intent: Intent, startId: Int) {
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)
        if (taskId.isNullOrBlank()) {
