            stopSelfResult(startId)
            return
        }

        val job = running[taskId]
        if (job == null) {
            Log.w(TAG, "Cancel ignored: taskId=$taskId not running")
            stopSelfResult(startId)
            return
        }

        Log.i(TAG, "Cancelling taskId=$taskId")
        job.cancel()
        stopSelfResult(startId)
    }

