        taskId: String,
        force: Boolean,
        dryRun: Boolean,
        target: String?,
        maxAgeDays: Int,
        callerTag: String?
    ) {
        withContext(Dispatchers.IO) {
            if (dryRun) {
                Log.i(TAG, "Cleanup(dryRun) taskId=$taskId target=$target force=$force maxAgeDays=$maxAgeDays callerTag=$callerTag")
                return@withContext
            }

            Log.i(TAG, "Cleanup(start) taskId=$taskId target=$target force=$force maxAgeDays=$maxAgeDays callerTag=$callerTag")

            // TODO: Replace with real cleanup logic (files/cache/db).
