            Thread.sleep(if (force) 1000L else 600L)

            Log.i(TAG, "Cleanup(done) taskId=$taskId")
        }
    }

    override fun onDestroy() {
        running.values.forEach { it.cancel() }
        running.clear()
        scope.cancel()
        super.onDestroy()
    }

    inner class LocalBinder : Binder() {
        fun getService(): MaintenanceTaskService = this@MaintenanceTaskService
        fun isTaskRunning(taskId: String): Boolean = running.containsKey(taskId)
        fun cancelTask(taskId: String) {
            running[taskId]?.cancel()
        }
    }
